import { Link } from 'react-router-dom';

import './Header.scss'

const Header = ({sidebarState, setSidebarState}) => {
    return (
        <div className="container">
            <div className="header">
                <button onClick={() => setSidebarState(!sidebarState)}>Menu</button>
                <Link to="/" className="link home">Home Page</Link>
                <Link to="/populars" className="link populars">Populars Page</Link>
                <Link to="/movies" className="link movies">Movies Page</Link>
                <Link to="/topFilms" className="link top-films">Top Films Page</Link>
                <Link to="/trillerPage" className="link triller-page">Triller Page</Link>
            </div>
        </div>
    )
}

export default Header;